import React, { useState, useEffect } from 'react';
import { 
  ChevronDownIcon,
  Squares2X2Icon,
  CheckIcon,
  CalendarIcon,
  BoltIcon,
  BellIcon,
  UserGroupIcon,
  ChartBarIcon,
  ClockIcon,
  PlayIcon,
  PauseIcon,
  StopIcon,
  CogIcon,
  ArrowRightOnRectangleIcon
} from '@heroicons/react/24/outline';

const Sidebar = () => {
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [reminders, setReminders] = useState([
    { id: 1, text: 'Review last update on the documentation for the event next week', completed: false },
    { id: 2, text: 'Check client\'s Q3 proposal', completed: true }
  ]);
  const [pomodoroActive, setPomodoroActive] = useState(false);
  const [pomodoroTime, setPomodoroTime] = useState(25 * 60); // 25 minutos em segundos
  const [currentPomodoro, setCurrentPomodoro] = useState(1);
  const [isAvailable, setIsAvailable] = useState(true);

  // Timer do Pomodoro
  useEffect(() => {
    let interval = null;
    if (pomodoroActive && pomodoroTime > 0) {
      interval = setInterval(() => {
        setPomodoroTime(time => time - 1);
      }, 1000);
    } else if (pomodoroTime === 0) {
      setPomodoroActive(false);
      // Próximo pomodoro
      if (currentPomodoro < 4) {
        setCurrentPomodoro(prev => prev + 1);
        setPomodoroTime(25 * 60);
      }
    }
    return () => clearInterval(interval);
  }, [pomodoroActive, pomodoroTime, currentPomodoro]);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const toggleReminder = (id) => {
    setReminders(prev => prev.map(reminder => 
      reminder.id === id ? { ...reminder, completed: !reminder.completed } : reminder
    ));
  };

  const startPomodoro = () => {
    setPomodoroActive(true);
  };

  const pausePomodoro = () => {
    setPomodoroActive(false);
  };

  const stopPomodoro = () => {
    setPomodoroActive(false);
    setPomodoroTime(25 * 60);
  };

  const navItems = [
    { icon: Squares2X2Icon, label: 'Dashboard', count: null },
    { icon: CheckIcon, label: 'To-dos', count: 2 },
    { icon: CalendarIcon, label: 'Schedule', count: null },
    { icon: BoltIcon, label: 'Nudge', count: null },
    { icon: BellIcon, label: 'Notifications', count: 5 },
    { icon: UserGroupIcon, label: 'Team', count: null },
    { icon: ChartBarIcon, label: 'Activity', count: null },
    { icon: ClockIcon, label: 'Reports', count: null }
  ];

  const bottomNavItems = [
    { icon: CogIcon, label: 'Settings' },
    { icon: ArrowRightOnRectangleIcon, label: 'Logout' }
  ];

  const uncompletedReminders = reminders.filter(r => !r.completed).length;

  return (
    <div className="w-full h-full bg-neutral-800 flex flex-col overflow-hidden">
      {/* Header com nome da empresa e dropdown */}
      <div className="p-4 border-b border-neutral-700">
        <button 
          onClick={() => setDropdownOpen(!dropdownOpen)}
          className="w-full flex items-center justify-between text-white hover:bg-neutral-700 rounded-lg p-2 transition-colors"
        >
          <span className="font-medium">Universe Reactive</span>
          <ChevronDownIcon className={`h-4 w-4 transition-transform ${dropdownOpen ? 'rotate-180' : ''}`} />
        </button>

        {dropdownOpen && (
          <div className="mt-2 bg-neutral-700 rounded-lg border border-neutral-600 shadow-lg">
            <div className="p-2">
              <div className="text-sm text-neutral-300 p-2 hover:bg-neutral-600 rounded cursor-pointer">Switch Organization</div>
              <div className="text-sm text-neutral-300 p-2 hover:bg-neutral-600 rounded cursor-pointer">Organization Settings</div>
            </div>
          </div>
        )}
      </div>

      {/* Navigation Links */}
      <div className="flex-1 overflow-y-auto">
        <div className="p-4 space-y-1">
          {navItems.map((item, index) => (
            <button
              key={index}
              className={`w-full flex items-center justify-between h-7 px-3 rounded-lg text-sm transition-colors hover:bg-neutral-700 ${
                item.label === 'Dashboard' ? 'bg-neutral-700 text-white' : 'text-neutral-300'
              }`}
            >
              <div className="flex items-center space-x-3">
                <item.icon className="h-4 w-4" />
                <span>{item.label}</span>
              </div>
              {item.count && (
                <span className="text-xs bg-neutral-600 text-neutral-300 px-2 py-0.5 rounded">
                  {item.count}
                </span>
              )}
            </button>
          ))}
        </div>

        {/* Reminders Section */}
        <div className="p-4">
          <div className="p-4">
            <div className="flex items-center justify-between mb-3">
              <h3 className="text-sm font-medium text-white">Reminders</h3>
              <span className="text-xs bg-neutral-600 text-neutral-300 px-2 py-0.5 rounded">
                {uncompletedReminders}
              </span>
            </div>
            <div className="border-t border-neutral-700 pt-3">
              <div className="space-y-3">
                {reminders.map((reminder) => (
                  <div key={reminder.id} className="flex items-start space-x-2">
                    <button
                      onClick={() => toggleReminder(reminder.id)}
                      className={`mt-0.5 w-4 h-4 border-2 flex items-center justify-center transition-colors ${
                        reminder.completed 
                          ? 'bg-green-500 border-green-500 rounded' 
                          : 'border-neutral-500 hover:border-neutral-400'
                      }`}
                    >
                      {reminder.completed && (
                        <CheckIcon className="h-3 w-3 text-white" />
                      )}
                    </button>
                    <span className={`text-xs ${
                      reminder.completed ? 'text-neutral-500 line-through' : 'text-neutral-300'
                    }`}>
                      {reminder.text}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Pomodoro Section */}
        <div className="px-4 pb-4">
          <div className="p-4">
            <h3 className="text-sm font-medium text-white mb-3">Working on Q4 Project</h3>

            {/* Pomodoro indicators */}
            <div className="flex space-x-1 mb-3">
              {[1, 2, 3, 4].map((num) => (
                <div
                  key={num}
                  className={`flex-1 h-1 rounded-full ${
                    num <= currentPomodoro ? 'bg-white' : 'bg-neutral-600'
                  }`}
                />
              ))}
            </div>

            {/* Timer */}
            <div className="flex items-center justify-between">
              <span className="text-lg font-mono text-white">{formatTime(pomodoroTime)}</span>
              <button
                onClick={pomodoroActive ? pausePomodoro : startPomodoro}
                className="p-2 bg-neutral-800 hover:bg-neutral-700 rounded transition-colors border border-neutral-600"
              >
                {pomodoroActive ? (
                  <PauseIcon className="h-4 w-4 text-white" />
                ) : (
                  <PlayIcon className="h-4 w-4 text-white" />
                )}
              </button>
            </div>
          </div>
        </div>

        {/* Available Toggle */}
        <div className="px-4 pb-4">
          <div className="bg-neutral-900 border border-neutral-700 rounded-lg p-4">
            <div className="flex items-center justify-between">
              <span className="text-sm text-white">Available</span>
              <button
                onClick={() => setIsAvailable(!isAvailable)}
                className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                  isAvailable ? 'bg-green-500' : 'bg-neutral-600'
                }`}
              >
                <span
                  className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                    isAvailable ? 'translate-x-6' : 'translate-x-1'
                  }`}
                />
              </button>
            </div>
          </div>
        </div>

        {/* Upgrade CTA */}
        <div className="px-4 pb-4">
          <button className="w-full bg-white text-black font-medium py-3 px-4 rounded-lg hover:bg-gray-100 transition-colors flex items-center justify-center space-x-2">
            <span>Upgrade to Pro</span>
            <BoltIcon className="h-4 w-4" />
          </button>
        </div>
      </div>

      {/* Bottom Navigation */}
      <div className="p-4 border-t border-neutral-700 space-y-1">
        {bottomNavItems.map((item, index) => (
          <button
            key={index}
            className="w-full flex items-center space-x-3 h-7 px-3 rounded-lg text-sm text-neutral-300 transition-colors hover:bg-neutral-700"
          >
            <item.icon className="h-4 w-4" />
            <span>{item.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
};

export default Sidebar;
